   146	static uint32_t eNB_app_register(uint32_t enb_id_start, uint32_t enb_id_end)
   147	{
   148	  uint32_t         enb_id;
   149	  MessageDef      *msg_p;
   150	  uint32_t         register_enb_pending = 0;
   151	
   152	  for (enb_id = enb_id_start; (enb_id < enb_id_end) ; enb_id++) {
   153	    // S1AP registration
   154	    /* note:  there is an implicit relationship between the data structure and the message name */
   155	    msg_p = itti_alloc_new_message(TASK_ENB_APP, 0, S1AP_REGISTER_ENB_REQ);
   156	    RCconfig_S1(msg_p, enb_id);
   157	
   158	    if (enb_id == 0)
   159	      RCconfig_gtpu();
   160	
   161	    LOG_I(ENB_APP, "default drx %d\n", ((S1AP_REGISTER_ENB_REQ(msg_p)).default_drx));
   162	
   163	    LOG_I(ENB_APP, "[eNB %d] eNB_app_register via S1AP for instance %d\n", enb_id, ENB_MODULE_ID_TO_INSTANCE(enb_id));
   164	    itti_send_msg_to_task(TASK_S1AP, ENB_MODULE_ID_TO_INSTANCE(enb_id), msg_p);
   165	
   166	    register_enb_pending++;
   167	  }
   168	
   169	  return register_enb_pending;
   170	}
